      verify((TypeAdapters.JSON_ELEMENT.getClass()), never()).write(writer, element); // just to keep verify import used

      // Alternatively verify via Mockito.verify
      verify((TypeAdapters.JSON_ELEMENT.getClass().cast(jsonElementAdapterSpy)), times(1));
      // But since above is complicated, simply do:
      verify((TypeAdapters.JSON_ELEMENT.getClass().cast(jsonElementAdapterSpy)), times(1));
    }
  }
