package com.google.gson.internal;

import static org.mockito.Mockito.*;

import com.google.gson.JsonElement;
import com.google.gson.internal.bind.TypeAdapters;
import com.google.gson.stream.JsonWriter;
import java.io.IOException;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class StreamsTest {

  @Test
  void write_CallsTypeAdaptersJsonElementWrite() throws Exception {
    JsonElement element = mock(JsonElement.class);
    JsonWriter writer = mock(JsonWriter.class);

    try (MockedStatic<TypeAdapters> typeAdaptersMockedStatic = Mockito.mockStatic(TypeAdapters.class)) {
      // Get the JSON_ELEMENT field via reflection
      Object jsonElementAdapter = TypeAdapters.class.getDeclaredField("JSON_ELEMENT").get(null);

      // Spy on the existing JSON_ELEMENT instance
      Object jsonElementAdapterSpy = spy(jsonElementAdapter);

      // Mock the static field access to return the spy
      typeAdaptersMockedStatic.when(() -> {
        return TypeAdapters.JSON_ELEMENT;
      }).thenReturn(jsonElementAdapterSpy);

      // Call the method under test
      Streams.write(element, writer);

      // Verify that write(writer, element) was called on the spy using reflection
      jsonElementAdapter.getClass()
          .getMethod("write", JsonWriter.class, JsonElement.class)
          .invoke(jsonElementAdapterSpy, writer, element);

      // Alternatively, verify using Mockito.verify with a cast
      verify((Object) jsonElementAdapterSpy, times(1)).write(writer, element);
    }
  }
}
```

**Note:** The last line `verify((Object) jsonElementAdapterSpy, times(1)).write(writer, element);` will not compile because `verify` expects a typed mock.

Since the type is unknown, you can use reflection to verify method invocation or use Mockito's `Mockito.verify` on the spy directly:

```java
// Cast to the interface or class that has write method
@SuppressWarnings("unchecked")
Class<Object> adapterClass = (Class<Object>) jsonElementAdapter.getClass();
adapterClass.getMethod("write", JsonWriter.class, JsonElement.class).invoke(jsonElementAdapterSpy, writer, element);
```

But reflection invocation does not verify method calls, it just calls the method.

So the best approach is to rely on Mockito spy verification:

```java
verify(jsonElementAdapterSpy).write(writer, element);
```

But since `jsonElementAdapterSpy` is of type Object, you need to cast it to an interface or class that declares `write`.

If `TypeAdapter` is not accessible, you can create an interface with the same method signature and cast to it:

```java
interface JsonElementWriter {
  void write(JsonWriter writer, JsonElement element) throws IOException;
}
```

Then cast:

```java
JsonElementWriter spyAdapter = (JsonElementWriter) jsonElementAdapterSpy;
verify(spyAdapter).write(writer, element);
```

